
-- 补遗漏的管理制度(117-120) + 财务剩余(121-139) + 供应链(141-155)

(gen_random_uuid(), 'kb/manage/117', '门店盈亏平衡分析制度', 'spec', '{管理,盈亏,分析}', '门店盈亏平衡分析三步法：1）固定成本统计——房租+人工+设备折旧+水电基础+保险+管理费用，明确月度固定支出；2）变动成本分析——礼品成本(营收25-35%)+营销费用(3-5%)+设备维修(2-3%)+税费；3）保本点计算——保本营收=固定成本/(1-变动成本率)。例：固定成本10万/月/变动成本率40%→保本营收16.7万。预警：连续3月低于保本点120%降本/连续6月低于保本点关店讨论。杠杆优化：租金降5%=利润提8-12%/客单价提5%=利润提15-25%/成本降5%=利润提10-20%。', '三步盈亏分析+预警机制+杠杆分析', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/manage/118', '门店周例会与月总结制度', 'spec', '{管理,会议,制度}', '周例会制度：周一30min全员参与+KPI回顾+本周目标+部门问题+表彰+行动项/专人记录+追踪完成。月总结制度：月5号前书面报告+全员会+报告结构(财务+运营+人员+项目+问题+计划)/店长→区域→总部逐级上报。会议产出：至少3个行动项+责任人+DDL+追踪闭环+次次会议核查。效率三原则：会前议程+会中控时+会后纪要。', '周会30min+月会全店+行动项追踪+三原则', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/manage/119', '新店筹备期管理制度', 'spec', '{管理,筹备,新店}', '新店筹备七阶段：M1(D-90)选址签约+品牌注册+团队搭建→M2(D-60)装修设计+消防设计+设备选型+证照申请→M3(D-45)施工+布线+安防+招聘→M4(D-30)设备到货安装+系统配置+培训→M5(D-14)验收+内测+试运营→M6(D-7)团购上架+营销预热+亲友试玩→M7(D-Day)开业活动+正式运营+首周复盘。每阶段独立预算+责任人+检查清单+跨阶段需前阶段100%完成。', '七阶段里程碑(90→0天)+预算/责任人/检查清单', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/manage/120', '物资采购管理制度', 'spec', '{管理,采购,制度}', '采购六步流程：需求→比价(≥3家)→审批(店长≤3000/区域≤10000/委员会>10000)→订单(系统下单+供应商确认)→验收(24h内数量质量规格)→付款(三单一致:发票+验收单+采购单)。采购分类：常规品月采购/紧急品店长权买/大额品委员会评审。比价要素：价格+运费+账期+质量+售后综合评价。', '六步采购+三级审批+三单一致', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/121', '预算执行监控与分析', 'spec', '{财务,预算,监控}', '预算监控三环：月度追踪(5号前出报告+实际vs预算+偏差原因)/预警(±10%黄/±20%红+整改)/调整(年中正式1次+专项特批)。分析三比：同比+环比+预算比。费用分可控(营销/采购/办公)和不可控(房租/折旧)。KPI：准确率≥90%/超预算发生率≤5%/平均幅度≤8%。', '三环监控+三比分析+预算准确率≥90%', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/122', '资金管理流程', 'spec', '{财务,资金,管理}', '资金管理四层：日报(16点收银盘点+次日12点前入账+日资金报表)/周报(周一编下周计划+收支预测+峰值低谷)/月报(25号前下月预测+月度偏差分析)/资金安全(现金不过夜+双人复核+月度银行对账+季度集团抽查)。周转目标：现金循环周期≤30天。', '四层资金(日/周/月/安全)+现金循环≤30天', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/123', '应收账款管理', 'spec', '{财务,应收,管理}', '应收四阶段：形成(合同账期+发票及时+台账登记)/催收(到期前7天提醒+到期日核实+逾期3天电话+7天上门+15天律师函+30天起诉)/坏账(单笔≤5000逾期90天可计提/年坏账率≤0.5%)/账龄分析(30/60/90/180天分段)。团购应收占营收30-50%，需每日核对平台结算单。', '四阶段应收+团购占30-50%需每日核对', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/124', '应付账款管理', 'spec', '{财务,应付,管理}', '应付五要素：分类(固定:房租人工/变动:采购/弹性:临时)/账期(60天采购+30天营销+月房租)/审批(四级:店长/区域/财务总监+运营/总经理)/支付(每周三统一+到期前3天复核)/优化(集中采购量换账期+供应链金融)。周转目标≥45天提升现金流。', '五要素应付+账期优化+周转目标≥45天', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/125', '固定资产管理', 'spec', '{财务,资产,管理}', '固定资产全流程：分类(设备5年/装修3年/IT 3年/家具5年)/入账(≥2000元+≥1年)/直线法折旧+月折旧=(原值-残值5%)/年限/12/年度盘点+季度抽查30%+差异处理/处置(报废/出售/捐赠)。神机营设备管理已实现台账+折旧+维修+ROI分析。', '五步资产全流程+神机营已实现台账/折旧/ROI', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/126', '无形资产与递延收益', 'spec', '{财务,递延,收益}', '电玩城特殊会计处理：无形资产(品牌/软件摊销3年/会员数据摊销5年)/递延收益(会员充值全款递延+消费释放+年费月线性确认+团购券核销确收+套餐拆分)。递延管理：月度明细(期初+充值+释放+余额)+占总营收30-50%+突降需调查。税务差异：递延税务或要求全额纳税/需递延所得税资产/负债。', '三类递延会计处理+税务差异+神机营P-38支持', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/127', '门店税务筹划', 'spec', '{财务,税务,筹划}', '四大税种筹划：增值税(一般纳税人6%/小规模3%/月收入≤10万免税/设备进项抵扣)/企业所得税(标准25%/小微2.5-10%/高新15%/研发加计100%)/附加税(城建7/5/1%+教育3%+地方2%)/个税(3-45%累进+年终奖单独+分红20%)。建议：新店前12月小规模→达标后转一般纳税人。红线：不虚开/不隐瞒/不虚构/不虚假认定。', '四大税种筹划+新店小规模先行+合规红线', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/128', '财务报表编制指南', 'spec', '{财务,报表,编制}', '三表编制：资产负债表(资产=负债+所有者权益)/利润表(收入-成本-费用=利润)/现金流量表(经营+投资+筹资)。频率：日报营收+现金流/月报三表/季报合并+分析/年报审计版。电玩城特殊科目：递延收益/预付卡负债/设备融资租赁/加盟保证金。', '三表编制+四频率+特殊科目+神机营P-38自动', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/129', '财务分析指标体系', 'spec', '{财务,指标,分析}', '四类15+指标：偿债(流动≥1.5/速动≥1/负债率<60%/利息倍数≥3)/营运(应收≤30天/库存≤45天/应付≥45天/现金循环)/盈利(毛利率≥60%/净利率≥15%/ROE≥30%/坪效500-1500/人效3-5万)/成长(营收≥15%/利润≥10%/会员≥20%)。三维对标：行业均值+竞品+自身历史。', '四类15+指标+三维对标+神机营KPI看板', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/130', '财务信息化管理', 'spec', '{财务,信息化,管理}', '四层信息化：数据层(业务系统→API/CDC→数据仓自动汇总)/对账层(银行vs系统自动+多支付聚合+差异跟踪)/核算层(自动凭证+科目映射+2工作日结账)/报告层(日报月报自动+管理驾驶舱+监管报送)。目标：手工减80%/结账快70%/财务转型分析决策。', '四层信息化+目标手工减80%/结账快70%', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/131', '内控与反舞弊', 'spec', '{财务,内控,反舞弊}', '十大风险点：收银(双人+系统+监控30天)/礼品(出入库双签+监控+盘点)/会员(消费验证+异常告警)/充值(财务每日三核对)/采购(比价3家+审计5%)/库存(月盘点+损耗≤2%)/报销(全量查验)/排班(考勤+绩效联动)/数据(脱敏+审批+日志)/账号(权限最小+季度审计)。反舞弊：举报热线+匿名+奖励20%追回+季度审计+年度培训。', '十大内控+反舞弊机制+神机营审计日志小时级', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/132', '投后管理与加盟监督', 'spec', '{财务,投后,加盟}', '投后三阶段：初期(0-3月)尽职调查+系统+培训+制度/常规(3-24月)月报+季现场审计+预警/退出(前6月)清算+盘点+债务+分配。加盟监督五重点：收入三核对/成本合规/管理费按时/品牌标准/合同合规。神机营多租户支持三级权限数据隔离。', '投后三阶段+加盟五监督+神机营多租户', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/133', '财务档案管理', 'spec', '{财务,档案,管理}', '五类档案+保存期限：凭证30年/账册30年/报表永久/合同10-30年/审计报告永久。管理要点：归档(月15号前凭证/30号前账册/季度电子备份)/存储(纸质18-22℃ 45-60%湿度/电子3-2-1备份)/调阅(填写+审批+登记+限时归还)/销毁(超期鉴定+审批+监督+清册存档)。', '五类档案+保存年限+3-2-1备份+销毁流程', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/134', '门店保险管理', 'spec', '{财务,保险,管理}', '四大险种：财产险(0.1-0.5%/年保设备装修库存)/公责险(建议100-500万/次 0.5-1.5%)/雇主险(200-500元/人/年)/营业中断险(2000-10000元/天 0.3-0.8%)。购买：到期前30天启动+多家比价+方案定制+审批+签约归档。理赔：48h内报案+证据+定损+修复完成。', '四大险种+购买五步+理赔流程', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/135', '经营决策财务支持', 'spec', '{财务,决策,支持}', '五种决策模型：定价(成本加成/竞争定价/价值定价)/促销(ROI≥1.5/打9折需量増11%/8折需25%)/设备采购(NPV≥0/IRR≥15%/回收期≤18月)/开店(回收≤24月/盈亏平衡≤6月/净利率≥15%)/关店(12月亏损+现金为负)。每个模型含假设+敏感性+推荐+风险。', '五种决策模型+敏感性分析+神机营可模拟', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/136', '财务对账自动化', 'spec', '{财务,对账,自动化}', '四类自动化对账：银行(API自动拉取+匹配+余额调节)/支付渠道(微信/支付宝/美团/抖音+三方对账)/会员卡(充值vs递延vs消耗)/团购(日核销vs系统vs银行)。自动化率目标：银行100%/支付≥95%/会员100%/团购≥90%。差异自动分类(时间差/手续费/退款/其他)/超24h自动升级。', '四类对账+目标≥90-100%+差异自动升级', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/137', '电子发票管理', 'spec', '{财务,发票,电子}', '电子发票全流程：开通(税务局+税控UKey+票种核定+限额)/开票(消费者申请→自动开票→短信/邮件/公众号推送)/冲红(有误/退货填红字信息表→自动冲红)/查验(国家查验平台+电子签名+归档PDF保10年)。效率：开票3min→30秒/降本80%/零纸质。', '五步电子发票+开票时间降80%+零纸质', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/138', '门店降本增效方案', 'spec', '{财务,降本,增效}', '十条实战方案：排班AI(降人工10-15%)/能耗LED+智能温控(月省3000-8000)/礼品批量采购+高性价比(降5-10%)/设备自修+保养(降维修15-25%)/营销砍低效(优化20-30%)/自动化对账(省1人/5店)/库存智能补货(降20%)/分时用电/内部审计/门店调拨(减少紧急采购)。总体可降本15-25%。', '降本十条+总体15-25%+AI排班+自动化审计', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/finance/139', '现金流预测模型', 'spec', '{财务,预测,现金流}', '三层现金流预测：日预测7天(营收+采购+工资+税费/准确率≥90%)/周预测4周(营收+支出+大额付款/≥85%)/月预测3月(基准+乐观+悲观三场景)。预警线：可用现金<月支出2月=黄/<1月=红+紧急融资。场景应对：乐观营收+20%/基准+5%/悲观-15%各给出对策。神机营支持三层预测+场景模拟。', '三层预测(日/周/月)+三场景+预警双线', 3, false, '{}'::jsonb, NOW(), NOW());

-- 供应链(141-155) 15篇 · 补全300篇
