INSERT INTO knowledge_documents (id, source_path, title, kind, tags, content, summary, chunk_count, is_archive, metadata, created_at, updated_at) VALUES
(gen_random_uuid(), 'kb/cross/276', '电玩城+音乐现场融合', 'spec', '{跨界,音乐,演出}', '电玩城音乐融合五种模式：1）驻唱舞台——每晚8-10点小型驻唱（歌手+吉他/键盘），成本1000-3000元/晚，吸引下班白领延长停留+酒水销售提升；2）DJ电音之夜——每周五/六DJ+灯光秀+舞池+同步大屏游戏画面，票价20-50元或免费入场（靠酒水消费）；3）音游竞赛——太鼓达人/舞萌DX/中二节奏/音击等音游周赛/月赛，音游玩家极硬核且回潮期；4）乐器体验区——电子鼓/电钢/竖琴/卡拉OK包房，15-30元/15分钟；5）音乐人合作——本地乐队联名歌单+月度不插电+联名周边。合规：噪音需专业隔音≤55dB/需表演权许可/23点限音。', '五种音乐融合模式+音游赛事+合规要点', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/cross/277', '电玩城+文旅地产协同', 'spec', '{跨界,地产,文旅}', '电玩城与地产文旅协同三种模式：1）购物中心主力店——签署10-15年租约，争取装修补贴200-500元/㎡+保底抽成6-10%；2）社区商业配套——500-800㎡辐射1-3km家庭客群，工作日儿童接送时段+周末全家出行；3）文旅地产配套——景区/度假村配建，客流季节性极强（节假日暴增60倍）。核心条款：租金减免期12-18个月、甲方出40-60%装修、主力店权责条款。交叉营销：与周边商户互导积分/联名券。', '三种地产合作模式+关键租约条款+交叉营销', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/cross/278', '电玩城+AI智能场景', 'spec', '{跨界,AI,智能}', 'AI六大落地场景：1）智能推荐——历史行为+表情分析实时推荐设备，提ARPU 15-25%；2）智能排班——客流预测+员工技能+成本约束自动排班，周自动生成+实时调整；3）智能客服——AI聊天机器人解答85%常见问题7x24，降人工40%；4）设备诊断——传感器监测+ML故障预测，提前48h预警；5）AI营销——RFM圈选+精准触达+自动A/B测试，ROI提30-50%；6）安全监控——视频分析识别异常事件（跌倒/抽烟/争吵），响应从5min缩至30s。技术：边缘本地推理+云端训练，脱敏保障合规，可迁移各市场部署。年投入30-80万（人力+算力+硬件），回本周期通常6-12个月。', '六大AI场景+技术架构+投入产出分析(年投入30-80万)', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/cross/279', '电玩城+潮流文化融合', 'spec', '{跨界,潮流,青年}', '青年潮流文化融合四方向：1）二次元圈层——痛机（动漫定制面板）+coser巡场500-2000元/场+限定吧唧徽章+国创IP联动；2）潮玩圈层——与泡泡玛特/TOP TOY合作（展示+兑换+售卖），潮玩市场2025规模1500亿+；3）街头文化——街舞月赛+DJ驻场+涂鸦墙+滑板/潮牌联名；4）电竞社交——电竞椅+240Hz显示器+5v5区+赛事合作5000-50万/场。全年活动日历：每月1次跨界主题（1-5万成本）+每季1次大活动（5-20万）。潮流用户LTV高出普通50-80%，是高价值核心客群。', '四大青年圈层(二次元/潮玩/街头/电竞)+全年节奏+LTV提升50-80%', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/cross/280', '电玩城+社交空间转型', 'spec', '{跨界,社交,空间}', '电玩城向社交空间转型方案：社交区——沙发+茶几+充电+桌游免费出借+打卡装置，延长停留30-60min，客单价提升8-15%。社群运营——按兴趣（赛车/拳皇/娃娃机）分群，每周主题之夜+群内福利+新设备内测。电竞赛事社交——每周小赛+月度城市赛+年度区域赛，观赛可押注（虚拟积分），营造社交氛围。活动型社交——缘分扭蛋活动+会员生日派对+匿名信等。跨业态社交合作——与隔壁奶茶/咖啡厅联名互导。目标：让客户不是为玩游戏而来，而是为社交空间顺便玩。', '社交化转型四要素(区域/社群/赛事/活动)+客户停留+30-60min', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/cross/281', '电玩城+KOL/内容创作者合作', 'spec', '{跨界,KOL,内容}', 'KOL合作四层矩阵：头部KOL（百万粉+，每市场1-2位/季）——品牌代言+探店视频+口播，预算20-200万/季度，适合品牌大事件。腰部KOL（10-50万粉，月度合作）——长期探店+测评+粉丝优惠，成本3-15万/次或利润分成。尾部+素人（1千-10万粉，批量每周20-50位）——免费体验+打卡+话题标签，低成本单客50-200元。MCN年框——与本地前3 MCN签约30-100万/年，保底KOL数量+内容条数+曝光。分成计划——API追踪KOL带来核销，佣金5-10%提成（18个月有效期）。运营：至少1名KOL对接专员/市场+创作日历+素材库+追踪仪表盘。年度预算占营销费30-50%，目标：单个KOL核销≥5倍费用。', 'KOL四层矩阵+分成模式+年度预算30-50%营销费', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/cross/282', '电玩城+运动健康融合', 'spec', '{跨界,运动,健康}', '运动健康融合三种路径：1）体感运动设备——互动骑行联网竞赛+体感拳击消耗卡路里+互动跑步AR+跳舞机DDR+篮球机，深受20-35岁女性+亲子欢迎，晚7-9点"下班燃脂局"定位。2）游戏化健身——"玩XX分钟得电子积分兑换礼品"+卡路里大赛（可穿戴设备门店互动）+限定运动手环。3）运动康复——热身区+拉伸指导+筋膜枪/泡沫轴放松点+健康轻食。健康融合运营成本低（免费/低成本改变），品牌差异化（"不只快乐还健康"）+拓宽女性客群+提高到店频率。体感运动设备投入2-8万/台，日均营收200-800元，回收期6-18个月。', '三种运动健康路径+低成本品牌差异+投资回收分析', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/cross/283', '电玩城+IP/内容深度运营', 'spec', '{跨界,IP,内容}', 'IP深度运营五步法：1）IP矩阵——全球级IP（迪士尼/漫威/宝可梦，授权费100-500万/年）+国潮IP（原神/故宫/敦煌，20-100万/年）+联合开发IP（与本地设计师共创新IP）。2）内容转化——IP主题设备外观+IP限定礼品（公仔/徽章/立牌/亚克力）+IP场景装饰（定期换主题）。3）粉丝运营——IP爱好者社群+限定购买权+IP主题日活动+coser巡场。4）IP生命周期管理——热门期（3-6月集中运营）+平缓期（降频维护）+换新（新IP接替）。5）IP效果评估——IP引入后营收提升率（目标≥20%）+新客占比（≥30%）+社媒曝光（200-500%+）+客户NPS。IP费用控制：年度IP总费用占营收≤10%，优选分成模式（低前期风险），次选买断模式（高控制力）。', 'IP五步深度运营法+生命周期管理+费用控制≤10%营收', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/cross/284', '电玩城+元宇宙虚实融合', 'spec', '{跨界,元宇宙,虚实}', '元宇宙虚实融合五方向：1）虚拟门店——Roblox/ZEPETO/Decentraland搭建品牌虚拟店，用户在线体验+领券→实体转化率1-3%；2）数字孪生——虚拟空间映射真实门店（设备占用/排队/礼品库存），用户远程查看后决策出行；3）虚拟商品——线上Avatar装扮/宠物/车辆（成本近0，毛利率80-95%）+线下充值解锁线上限定；4）跨服社交——APP基于LBS匹配附近玩家+跨店约战+跨城友谊赛；5）数字人营销——AI虚拟偶像24/7直播带货+品牌代言，成本远低于真人KOL。轻量化第一步：数字孪生（门店热度图+设备实时状态公开）+简单虚拟物品（Avatar+排行榜），额外投入5-10万。', '五个元宇宙方向+首步轻量化方案(5-10万投入)', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/cross/285', '电玩城+新零售融合发展', 'spec', '{跨界,零售,融合}', '新零售融合四种模式：1）智能货柜——商品扫码自助付款，玩具/零食/潮玩SKU30-50个，月均2000-5000元/柜，节省收银人力1-2人/店；2）积分兑换零售——积分商城+自助兑换机，积分消耗率目标≥30%，推动会员活跃+降低礼品采购成本；3）社交电商——设备外屏显示可邮购独家商品，扫码付款→快递到家/门店自提；4）O2O体验——线上下单（小红书/抖音挂车）→到店核销/体验+离店后追销。融合难点：库存系统需打通+区隔经营品类（娱乐证不可卖常规零售，仅限食品/饮料/游戏币+关联品）。推荐路径：电子商品（卡券）+线下体验触发线上消费，避开复杂零售许可。', '四种零售融合+经营许可合规+推荐电子化轻路径', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/cross/286', '电玩城+本地文化/非遗融合', 'spec', '{跨界,文化,非遗}', '本地文化/非遗融合四方向：1）本地特色礼品——城市地标/吉祥物/非遗IP定制限定娃娃/手办/徽章，兑换率提升50-100%+成为游客打卡伴手礼；2）本地游戏内容——设备UI融入地方民俗（赛龙舟模拟/麻将风格/地方美食烹饪模拟）；3）传统节日活动——春节/元宵/端午/中秋改造成电玩主题活动（投壶/猜灯谜/射箭模拟）；4）非遗合作——与传承人/博物馆合作主题盲盒+体验工坊+DIY制作区。效果：本地礼品提升20-30%重复到访率+活动促进社交传播+非遗合作获文化部门正面关注+可争取活动补贴/文创资金。投入成本：礼品定制开模摊销0.5-2元/件+活动成本3000-10000元/次。', '四方向本地文化融合+效果(兑换率50-100%+复购20-30%)+补贴机会', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/cross/287', '电玩城+动漫二次元深度整合', 'spec', '{跨界,动漫,二次元}', '二次元深度整合五方案：1）长期IP合作——集英社/讲谈社/角川/国创IP，授权费20-100万/年，毛利率30-40%；2）主题月活动——每月一部IP主题改造（贴膜+海报+地贴+岛台），限定周边集中展示，刺激高复购；3）痛机专区——5-10台IP定制外观设备（面板+UI+音效），打卡拍照自发传播=获客成本0，可做成可更换面板的固定装置；4）二次元社群——微信群新番安利/展会拼单/谷子交换/群内专属抽选；5）同人创作激励——画手来店免费创作+作品展示+社交传播。二次元客群特征：15-30岁，消费忠诚高，复购频率每周1-3次（远高于普通用户月1-2次），极度重视正版授权。', '五大二次元整合方案+痛机专区+社群运营', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/cross/288', '电玩城+餐饮深度融合', 'spec', '{跨界,餐饮,融合}', '三种餐饮融合模式：轻餐吧（15-30㎡+吧台，营收10-15%，毛利率60-70%）——饮品/冰淇淋/爆米花/热狗，投资2-5万，适合400-800㎡店。主题餐厅（80-120㎡+40-60座位，营收20-30%，毛利率55-65%）——中式简餐/西式扒饭，需完整餐饮团队+厨房设备15-30万，适合≥800㎡大店。社交轻酒吧（21:00切换模式，营收30-50%，毛利率65-75%）——灯光+音乐+酒水，需酒牌（各地办理时间不同，中东穆斯林国家基本不可行）。关键要点：动线分区（气味/噪音隔离）+净化系统（油烟处理+新风按餐饮标准）+账务统一（会员积分跨品类）+时间复用（餐饮先于游戏营业：早餐+茶饮+午餐）+分品类核算坪效。', '三种餐饮融合(轻餐/餐厅/酒吧)+分区/空气/账务/时间要点', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/cross/289', '电玩城+企业服务B端', 'spec', '{跨界,企业,B端}', 'B端服务三大产品：企业团建（30人/50人/100人三档标准化方案+定制，128-298元/人，毛利率50-60%，含体验+比赛+茶歇+伴手礼，开企业发票）。企业年会/发布会（包场非营业时段+设备游览+大屏+Led舞台+餐饮，定价1-5万/场）。员工福利（入驻企业福利平台如携程/美团企业版，企业采购优惠券/月卡/季卡发员工，零售价7-8折）。获客渠道：BD团队对接本地大企业HR/行政/工会+企业服务采购平台+行业协会+Boss直聘企业会员+老客转介绍。B端客户占营收目标5-10%，价格敏感度低于C端+预约稳定+平日白天填满场地空闲时段。', '三大B端产品线(团建/年会/福利)+获客渠道+占营收5-10%', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/cross/290', '电玩城+宠物经济融合', 'spec', '{跨界,宠物,经济}', '宠物经济融合三种模式：猫咖+电玩（独立分区+人猫分离空气+吸猫边玩游戏，受众20-35岁女性高度重合，猫咖门票38-68元/时+食品饮料，延长停留150%+）。宠物礼品区（宠物小玩偶/猫狗兔子造型娃娃做机台礼品，兑换率20-25%，女性吸引力高+男性送礼需求，宠物主题兑换率高普通30-50%）。领养公益活动（每月与流浪动物组织合作，游戏互动积累爱心分可领养，提升好感度+公益性质抵税）。风险：卫生与动物福利（兽医巡视+清洁消毒+隔离）+过敏源/毛发/气味+监管限制（部分城市严格限制商场养动物需环境评估）。推荐度：猫咖***/宠物周边****/公益领养*****', '三种宠物融合+收益风险分析+推荐度对比', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/esg/291', 'ESG战略框架与可持续运营', 'spec', '{ESG,战略,可持续}', '电玩城ESG战略三支柱框架：环境（Environment）——碳排放管理（年碳足迹基线测量+碳中和路线图+绿色电力采购）、能效优化（LED 100%替换+空调Smart Control+设备自动休眠）、水资源管理（节水器具+废水处理+雨水收集）、废弃物管理（垃圾分类+回收率≥50%+一次性塑料减量）。社会（Social）——员工权益（公平薪酬+安全健康+培训成长+多元化包容）、客户安全（设备安全标准+数据隐私+未成年保护）、社区关系（就业贡献+公益活动+青少年发展）。治理（Governance）——ESG委员会（CEO+CFO+CSO）、ESG报告（年度GRI标准报告+第三方鉴证）、风险管理（ESG风险评估+供应链ESG审计+合规监控）。实施路线：第1年基线测量+政策制定（环境数据基线/ESG政策框架）→第2年目标落地+报告（ESG KPI管理/首次报告）→第3年闭环提升+认证（碳中和项目/ISO认证）。ESG投入：年运营成本0.5-1.5%（初期投入略高，3年回本通过能效节省+品牌溢价+绿色金融优惠）。', 'ESG三支柱(环境/社会/治理)+三年实施路线+投入0.5-1.5%营收', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/esg/292', '碳排放管理与碳中和路线图', 'spec', '{ESG,碳,中和}', '电玩城碳中和路线图三步走：Scope 1直接排放（设备天然气+公司车辆燃料）≈5%、Scope 2间接排放（外购电力≈75%为主）≈75%、Scope 3价值链排放（供应商+客户交通+废弃物≈20%）。测基线：年度总排放CO2e（ton）=用电量MWh×电网排放因子+燃气m³×因子+冷媒泄漏+车辆燃油+商务飞行。减排措施：LED+Smart AC（减Scope2 30%）+屋顶光伏（自发电覆盖20-40%）+绿电采购合同（确保100%可再生电力）。碳抵消：购买VER/VCS碳信用（¥30-80/ton）+植树造林+社区碳项目支持。目标里程碑：2026基线测量→2027年碳排放减少20%（vs基线）→2028减少50%→2030碳达峰→2035碳中和（净零）。预算：碳管理年¥50,000-150,000/百店（测量+减排+认证+抵消）。报告：CDP披露+TCFD框架+年度ESG报告+第三方鉴证+可追溯的碳抵消证书。', '碳排放三Scope+测量+减排+抵消+2035碳中和路线', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/esg/293', '绿色门店标准与认证', 'spec', '{ESG,绿色,认证}', '绿色门店标准六维评估体系：一、能源效率（30分）——LED 100%覆盖率（10分）+空调能效比≥一级（10分）+智能能耗管理系统（10分）。二、水效（15分）——节水洁具（5分）+废水回收利用（5分）+雨水收集系统（5分）。三、材料与资源（20分）——装修可回收材料≥50%（10分）+FSC认证木材（5分）+无VOC涂料（5分）。四、室内环境（15分）——空气质量监测（5分）+自然采光率（5分）+噪音控制≤45dB（5分）。五、废弃物管理（10分）——垃圾分类设施（5分）+回收率≥60%（5分）。六、创新（10分）——可再生能源+碳捕捉+生物多样性等加分项。绿色门店认证选择：LEED（国际认可，认证费¥50-200K/店）、BREEAM（欧洲标准）、中国绿色建筑评价标识（国内成本低）。经济测算：绿色门店建设投入高15-20%但运营5年节省25-35%（电费+水费+维修+政策补贴），政府提供绿色信贷优惠利率（低20-50bp）+税费减免。', '六维绿色门店评分+LEED/BREEAM认证+经济测算', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/esg/294', '供应链ESG管理', 'spec', '{ESG,供应链,管理}', '供应链ESG管理四步法：1）ESG准入——供应商ESG问卷（环保认证+劳工权益+反腐败+数据安全）评分≥60分才准入，年度审核+降级机制。2）绿色采购——优先采购环保材质礼品（可降解/再生材料）+能源之星认证设备+环境标志办公用品+绿色包装（减量+可回收），绿色采购占比目标≥30%并逐年提升10%。3）劳工与人权——抵制强制劳动/童工（供应商签署工人权益承诺书+年度劳动审计），安全健康（供应商工厂安全检查+ISO 45001认证优先），公平工资（供应商支付≥当地最低工资+社保）。4）反腐与合规——反腐败条款写入合同+举报机制+合作关系信息公开+季度供应商廉洁度评估。供应商审计分级：高ESG风险（如化学品/电子制造供应商）年度全面审计+中风险（普通礼品/包材）年度问卷+低风险（办公耗材）两年一次。审计不达标处理：60天限期整改→不合格降级→连续2次不达标终止合作。', '四步供应链ESG管理+供应商审计分级+不达标处理机制', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/esg/295', '员工权益与多元化管理', 'spec', '{ESG,员工,权益}', '员工权益ESG管理五维度：1）公平就业——招聘无歧视（性别/年龄/宗教/残疾），薪酬透明+同工同酬年度审计，多元化团队建设（管理岗女性占比目标≥40%+残疾人岗位≥2%）。2）健康安全——OHSAS 18001/ISO 45001认证，年度全员体检+心理健康服务（EAP员工援助计划）+工作环境安全标准。3）培训发展——人均培训时数目标≥40h/年+培训覆盖率≥95%+培训成果转化率跟踪。4）员工参与——年度员工满意度调查（目标≥4.0/5.0）+员工代表委员会+季度全员沟通会+建议奖励制度（采纳率≥10%）。5）薪酬福利——≥当地最低工资150%+社保公积金全额+弹性福利包（可选健身/学习/保险等）+利润分享（店长+核心员工）+带薪休假高于法定标准。ESG员工指标报告：女性占比/女性管理层占比/培训总时数/工伤率/员工满意度/流失率/人均薪酬增长。', '五维员工ESG管理+关键报告指标+福利体系', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/esg/296', '社区关系与CSR管理', 'spec', '{ESG,社区,CSR}', '社区关系与CSR四大领域：1）教育支持——青少年科技/电竞教育课程（与学校合作STEAM研学）+奖学金+实习基地+设备捐赠。2）社区发展——社区活动空间免费开放时段+邻里活动+扶助弱势群体+支持本地小商户（优先本地采购+合办活动）。3）环境贡献——门店周边清洁/植树活动+减碳宣传教育+绿色消费倡导（可降解礼品兑换+自带杯优惠）。4）紧急援助——灾害后提供场地做临时避险+捐助物资+员工志愿服务。CSR组织：总部CSR委员会+门店CSR大使（兼职）。年度CSR预算：利润的1-2%或营收的0.3-0.5%。管理要求：项目立项→预算→执行→效果评估→报告。年度CSR报告（中英文）→公开披露→第三方评估可选。关键KPI：CSR项目数量（年≥10个）+受益人数（年≥10,000人）+员工志愿参与率（≥50%）+CSR品牌曝光+社区满意度调查≥4.0。', '四大CSR领域(教育/社区/环境/援助)+预算1-2%利润+年度CSR报告', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/esg/297', '数据隐私与客户保护', 'spec', '{ESG,隐私,保护}', '数据隐私与客户保护五层体系：1）合规框架——遵循各市场数据保护法（GDPR/CCPA/PDPA/PIPA/APPI），数据处理协议+隐私影响评估（PIA）+DPO任命+数据保护官培训。2）数据治理——数据分类分级（PII/敏感/内部/公开），最小化采集原则（只收所需+告知目的+获取同意），保留期限管理（1-5年自动清理）。3）安全措施——静态加密（AES-256）+传输加密（TLS 1.3）+访问控制（RBAC+最小权限）+审计日志。4）用户权利——知情权/访问权/更正权/删除权/可携带权/反对权，用户请求72h内响应+30天内完成处理。5）应急响应——数据泄露72h内通知监管+受影响用户+公关处理+根因分析+改进措施。年度预算：营收的0.5-1.5%（含系统+工具+人员+审计+保险+培训）。KPI：数据泄露事件0/用户隐私投诉率≤0.01%/隐私合规审计100%通过率。', '五层数据隐私保护体系+用户权利+应急响应+年度预算', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/esg/298', 'ESG报告编制标准', 'spec', '{ESG,报告,标准}', 'ESG报告编制标准参照GRI（全球报告倡议组织）2021标准：一般披露（GRI 2）——组织概况/治理/战略/利益相关方参与/报告实践。实质性议题（GRI 3）——实质性评估流程+实质性议题清单+矩阵。经济议题（GRI 201-207）——经济绩效/市场表现/间接经济影响/采购实践/反腐败/税务。环境议题（GRI 301-308）——物料/能源/水/生物多样性/排放/废弃物/供应商环境评估。社会议题（GRI 401-418）——雇佣/劳资关系/职业健康安全/培训/多元化/平等机会/不歧视/结社自由/童工/强迫劳动/安保/原住民权利/人权评估/本地社区/供应商社会评估/公共政策/客户健康安全/营销标识/客户隐私/社会经济合规。报告编制流程：实质性评估（利益相关方调研+管理层访谈）→数据收集（各业务部门+供应链+各市场）→编制报告（GRI索引+数据表+案例）→外部鉴证（可选/推荐）→发布（官网+监管平台+行业排名）。', 'GRI标准ESG报告编制+数据收集+外部鉴证+发布', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/esg/299', '可持续金融与绿色融资', 'spec', '{ESG,金融,融资}', '可持续金融工具与应用：绿色贷款——专项用于绿色门店建设/节能改造/可再生能源项目，利率优惠20-50bp（vs普通贷款）+审批绿色通道+可享受央行碳减排支持工具。可持续发展挂钩贷款（SLL）——利率与ESG KPI（碳排放减少/绿色采购占比/员工满意度）挂钩，达标享受利率降幅（5-15bp/指标），需第三方验证+年度报告。绿色债券——募集资金用于绿色项目（门店节能改造/绿色供应链/碳减排），需绿色债券认证+第三方评估+年度信息披露。ESG投资/Impact Investing——对接ESG基金/影响力投资机构（关注环境+社会效益），估值溢价5-15%（vs普通公司）。碳交易——参与全国碳排放权交易市场（如有配额）+自愿减排交易（CCER）出售碳信用。ESG评级提升价值：MSCI/ISS/Sustainalytics评级提升→降低融资成本（50bp+）+吸引ESG投资者（占比全球机构资产30%+并持续增长）。', '五种可持续金融工具+ESG评级提升降低融资成本50bp+', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/esg/300', '神机营行业愿景与未来展望', 'spec', '{未来,愿景,展望}', '神机营SaaS电玩城行业未来10年展望（2026-2036）：到2028年，全国FEC市场预计1,200亿元（CAGR 15%+），连锁化率从15%提升至30%，前10品牌占据40%市场份额。神机营定位：电玩城连锁化基础设施——一站式SaaS+AI+IoT+数据平台让中小品牌也能拥有集团级运营能力。技术演进：L3（规则引擎AI）+L4（机器学习预测）+L5（自主决策AI运营助手），AI替代率从当前20%→2030年60%+（排班/对账/营销/客服/诊断/预测全面自动化）。全球视野：中国FEC出海东南亚→中东→拉美（2030年海外门店占30%营收），参考泡泡玛特/完美日记/海底捞出海路径。行业归属：从"游戏游艺"向"家庭娱乐中心FEC"→"线下社交空间"→"体验式新零售"演变，坪效从500元/㎡/月提升至1,500元（2030年）。神机营愿景：让每一家电玩城都拥有超级运营大脑（AI驱动+数据智能+自动化决策），成为全球FEC行业最值得信赖的技术伙伴。', '行业10年展望(1200亿市场/AI自动化/全球化/愿景)', 3, false, '{}'::jsonb, NOW(), NOW());
INSERT INTO knowledge_documents (id, source_path, title, kind, tags, content, summary, chunk_count, is_archive, metadata, created_at, updated_at) VALUES
INSERT INTO knowledge_documents (id, source_path, title, kind, tags, content, summary, chunk_count, is_archive, metadata, created_at, updated_at) VALUES
(gen_random_uuid(), 'kb/supply/141', '供应商管理流程', 'spec', '{供应链,供应商,管理}', '供应商管理四阶段：准入(资质审核+样品+首批试单≤5000+建档)/分级(A战略年50万+账期60天/B主力10-50万/45天/C补充1-10万/30天/D淘汰)/评估(质量30%+价格25%+交期20%+服务15%+合规10%)/合作(年框协议+月对账+年谈判量换价)。季度末位淘汰。', '四阶段供应商管理+季度末位淘汰', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/supply/142', '采购比价与谈判策略', 'spec', '{供应链,采购,谈判}', '比价三步：寻源(≥3家含1家新供应商+统一规格报价)/比价(TCO总成本+性价比+综合评分)/谈判(锚定+量换价5-15%+账期杠杆+组合+备胎)。底线：不超预算10%+账期≤60天+质保≥1年。三权分立：采购/审批/验收分人+季度审计。', '三步比价谈判+底线+三权分立', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/supply/143', '礼品选品与趋势分析', 'spec', '{供应链,礼品,选品}', '选品四大策略：热门IP(动漫/国潮/影视/游戏)/分层(引流品成本2-5元+主力10-30/高端50-200)/趋势(盲盒持续火+DIY手作+联名款)/淘汰(月兑<1%降价/季<3%清仓/年<10%淘汰)。数据驱动：热销Top10+年龄段+客单价+季节规律。', '四大选品策略+数据淘汰+神机营ABC分析', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/supply/144', '设备采购选型标准', 'spec', '{供应链,设备,采购}', '六维评估：品牌20分(国际一线/国内/二线)/性能25分(游戏性+画质+交互)/耐用20分(MTBF≥5000h+工业级)/维保15分(配件≥5年+响应≤24h)/价格10分/ROI 10分(回收≤12月=10/≤18=7/≤24=4)。综合≥80推荐/60-79讨论/<60放弃。', '六维设备评估+综合≥80推荐', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/supply/145', '设备融资租赁分析', 'spec', '{供应链,融资,租赁}', '三种融资方式：直租(租赁公司买设备门店月租36-60月/期满归门店/利率8-12%)/回租(自有设备卖+回租一次性得60-80%价值/利率6-10%)/分期(首付30-50%+12-24期/利率0-5%)。决策因素：折合年化利率/税务影响(租金可抵扣/分期利息可抵)/现金流平滑度。', '三种融资方式(直租/回租/分期)+利率对比', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/supply/146', '礼品库存周转优化', 'spec', '{供应链,库存,周转}', '库存优化六策略：ABC分类(A周度/B月度/C季度)/安全库存(A备120%/B 80%/C 50%)/滞销处理(月盘点→降价→打包→捐赠→淘汰)/换季管理(IP提前45天备/节后1月出清)/数字化(RFID+智能补货)/KPI(周转≤45天/现货≥90%/滞销≤15%/损耗≤2%)。', '六策略库存优化+KPI周转≤45天', 3, false, '{}'::jsonb, NOW(), NOW()),
